SELECT ?player ?bestRank (COUNT(?title) AS ?titles) WHERE {
  wd:Q2070302 wdt:P710 ?player .
  ?player wdt:P1535 ?bestRank .
  OPTIONAL {
    ?title wdt:P170 ?player .
    ?title wdt:P361 wd:Q1360577 .
    ?title wdt:P582 ?titleEnd .
    FILTER(?titleEnd <= "2002-02-10T00:00:00Z"^^xsd:dateTime)
  }
} GROUP BY ?player ?bestRank ORDER BY ?bestRank ASC ?titles DESC LIMIT 1 OFFSET 2

SELECT ?player ?bestRank (COUNT(?title) AS ?title_count) WHERE {
  wd:Q2070302 wdt:P710 ?player .
  ?player wdt:P1535 ?bestRank .
  OPTIONAL {
    ?title wdt:P361 wd:Q1360577 .
    ?title wdt:P170 ?player .
    ?title wdt:P582 ?endDate .
    FILTER(?endDate < "2002-02-03T00:00:00Z"^^xsd:dateTime)
  }
} GROUP BY ?player ?bestRank
ORDER BY ?bestRank ASC ?title_count DESC
LIMIT 1 OFFSET 2

